+  <body>
+    <div class="wrap">
+      <div class="app">
+        <section class="panel board" aria-label="Snake game">
+          <div class="header">
+            <div class="title">
+              <h1>Snake</h1>
+              <span class="pill" id="statusPill">Ready</span>
+            </div>
+            <div class="stats" aria-label="Score">
+              <div class="stat" aria-live="polite">
+                <div class="k">SCORE</div>
+                <div class="v" id="score">0</div>
+              </div>
+              <div class="stat" aria-live="polite">
+                <div class="k">BEST</div>
+                <div class="v" id="best">0</div>
+              </div>
+            </div>
+          </div>
+
+          <div class="canvasWrap">
+            <canvas id="game" width="600" height="600" aria-label="Snake board"></canvas>
+            <div class="overlay" aria-hidden="false">
+              <div class="overlayCard" id="overlayCard">
+                <p class="overlayTitle" id="overlayTitle">Snake</p>
+                <p class="overlayMsg" id="overlayMsg">
+                  Use arrow keys to move. Eat the orb. Don’t hit the walls or yourself.
+                </p>
+                <div class="overlayRow">
+                  <button id="btnStart" type="button">Start</button>
+                  <button id="btnRestart" type="button" class="secondary">Restart</button>
+                </div>
+                <p class="footerNote">Tip: press <span style="font-family: var(--mono)">Space</span> to restart.</p>
+              </div>
+            </div>
+          </div>
+          <p class="srOnly" id="ariaUpdates" aria-live="polite"></p>
+        </section>
+
+        <aside class="panel side" aria-label="Instructions">
+          <h2>Controls</h2>
+          <div class="kbdRow" aria-hidden="true">
+            <kbd>↑</kbd><kbd>↓</kbd><kbd>←</kbd><kbd>→</kbd>
+            <kbd>Space</kbd>
+          </div>
+          <div class="help">
+            Arrow keys steer the snake. Each orb increases your score and slightly ramps speed.
+            If the tab loses focus, the game pauses.
+          </div>
+          <div class="controls" style="margin-top: 14px;">
+            <button id="btnPause" class="ghost" type="button">Pause</button>
+            <button id="btnResume" class="ghost" type="button">Resume</button>
