+    </div>
+
+    <script>
+      (() => {
+        "use strict";
+
+        const canvas = document.getElementById("game");
+        const ctx = canvas.getContext("2d", { alpha: true });
+        const scoreEl = document.getElementById("score");
+        const bestEl = document.getElementById("best");
+        const statusPill = document.getElementById("statusPill");
+        const ariaUpdates = document.getElementById("ariaUpdates");
+
+        const overlayCard = document.getElementById("overlayCard");
+        const overlayTitle = document.getElementById("overlayTitle");
+        const overlayMsg = document.getElementById("overlayMsg");
+        const btnStart = document.getElementById("btnStart");
+        const btnRestart = document.getElementById("btnRestart");
+        const btnPause = document.getElementById("btnPause");
+        const btnResume = document.getElementById("btnResume");
+
+        // Grid is logical; canvas is scaled for crisp rendering.
+        const GRID = 22;
+        const BASE_TPS = 8.5; // ticks per second
+        const MAX_TPS = 17.0;
+
+        const LS_BEST_KEY = "snake.bestScore.v1";
+        const bestFromStorage = Number.parseInt(localStorage.getItem(LS_BEST_KEY) || "0", 10);
+        let bestScore = Number.isFinite(bestFromStorage) ? bestFromStorage : 0;
+        bestEl.textContent = String(bestScore);
+
+        const dirs = {
+          ArrowUp: { x: 0, y: -1 },
+          ArrowDown: { x: 0, y: 1 },
+          ArrowLeft: { x: -1, y: 0 },
+          ArrowRight: { x: 1, y: 0 },
+        };
+
+        const clamp = (v, a, b) => Math.max(a, Math.min(b, v));
+
+        function setPill(text, tone) {
+          statusPill.textContent = text;
+          const toneToBg = {
+            ready: "rgba(255,255,255,0.06)",
+            playing: "rgba(106, 228, 255, 0.10)",
+            paused: "rgba(167, 139, 250, 0.10)",
+            over: "rgba(255, 90, 122, 0.10)",
+          };
+          statusPill.style.background = toneToBg[tone] || toneToBg.ready;
+          statusPill.style.borderColor = "rgba(255,255,255,0.12)";
+          statusPill.style.color = "rgba(255,255,255,0.80)";
+        }
+
+        function announce(msg) {
+          ariaUpdates.textContent = msg;
+        }
+
+        function randInt(n) {
+          return Math.floor(Math.random() * n);
+        }
+
+        function key(x, y) {
+          return x + "," + y;
+        }
+
+        function placeFood(occupiedSet) {
+          // Try random picks first, then fall back to a scan.
+          for (let i = 0; i < 80; i++) {
+            const fx = randInt(GRID);
+            const fy = randInt(GRID);
+            if (!occupiedSet.has(key(fx, fy))) return { x: fx, y: fy };
+          }
+          for (let y = 0; y < GRID; y++) {
+            for (let x = 0; x < GRID; x++) {
+              if (!occupiedSet.has(key(x, y))) return { x, y };
+            }
+          }
+          return null;
+        }
+
+        let snake;
+        let dir;
+        let queuedDir;
+        let food;
+        let score;
+        let tps;
+        let running = false;
+        let paused = false;
+        let gameOver = false;
+
+        let lastTime = 0;
+        let acc = 0;
+
+        function resetGame() {
+          // Start centered, moving right.
+          const mid = Math.floor(GRID / 2);
+          snake = [
+            { x: mid - 2, y: mid },
+            { x: mid - 1, y: mid },
+            { x: mid, y: mid },
+          ];
+          dir = { x: 1, y: 0 };
+          queuedDir = null;
+          score = 0;
+          tps = BASE_TPS;
+          running = false;
+          paused = false;
+          gameOver = false;
+
+          const occ = new Set(snake.map((p) => key(p.x, p.y)));
+          food = placeFood(occ);
+          updateHUD();
+          setPill("Ready", "ready");
+          showOverlay("Snake", "Use arrow keys to move. Eat the orb. Don’t hit the walls or yourself.");
+          draw();
+        }
+
+        function start() {
+          if (gameOver) return;
+          if (running && !paused) return;
+          running = true;
+          paused = false;
+          setPill("Playing", "playing");
+          hideOverlay();
+          announce("Game started");
+          lastTime = performance.now();
+          acc = 0;
+          requestAnimationFrame(frame);
+        }
+
+        function restart() {
+          resetGame();
+          start();
+        }
+
+        function pause() {
+          if (!running || gameOver) return;
+          paused = true;
+          setPill("Paused", "paused");
+          showOverlay("Paused", "Press Resume or hit Enter to continue.");
+          announce("Game paused");
+        }
+
+        function resume() {
+          if (!running || gameOver) return;
+          if (!paused) return;
+          paused = false;
+          setPill("Playing", "playing");
+          hideOverlay();
+          announce("Game resumed");
+          lastTime = performance.now();
+          acc = 0;
+          requestAnimationFrame(frame);
+        }
+
+        function end(reason) {
+          gameOver = true;
+          running = false;
+          paused = false;
+          setPill("Game Over", "over");
+
+          const msg =
+            (reason ? reason + ". " : "") +
+            `Final score: ${score}. Press Space to restart.`;
+
+          showOverlay("Game Over", msg);
+          announce("Game over. " + msg);
+
+          if (score > bestScore) {
+            bestScore = score;
+            localStorage.setItem(LS_BEST_KEY, String(bestScore));
+            bestEl.textContent = String(bestScore);
+          }
+        }
+
+        function updateHUD() {
+          scoreEl.textContent = String(score);
+          bestEl.textContent = String(bestScore);
+        }
+
+        function showOverlay(title, msg) {
+          overlayTitle.textContent = title;
+          overlayMsg.textContent = msg;
+          overlayCard.hidden = false;
+        }
+
+        function hideOverlay() {
+          overlayCard.hidden = true;
+        }
+
+        function setDirection(next) {
+          // Prevent instantaneous reversal.
+          if (!next) return;
+          const current = queuedDir || dir;
+          if (current.x + next.x === 0 && current.y + next.y === 0) return;
+          queuedDir = next;
+          if (!running && !gameOver) start();
+        }
+
+        function step() {
+          if (!running || paused || gameOver) return;
+
+          if (queuedDir) {
+            dir = queuedDir;
+            queuedDir = null;
+          }
+
+          const head = snake[snake.length - 1];
+          const nx = head.x + dir.x;
+          const ny = head.y + dir.y;
+
+          if (nx < 0 || ny < 0 || nx >= GRID || ny >= GRID) {
+            end("You hit a wall");
+            return;
+          }
+
+          const nextKey = key(nx, ny);
+
+          // If we are not growing, the tail will move away, so allow moving into current tail.
+          const willEat = food && nx === food.x && ny === food.y;
+          const tail = snake[0];
+          const tailKey = key(tail.x, tail.y);
+          const bodySet = new Set(snake.map((p) => key(p.x, p.y)));
+          if (bodySet.has(nextKey) && !( !willEat && nextKey === tailKey)) {
+            end("You ran into yourself");
+            return;
+          }
+
+          // Advance.
+          snake.push({ x: nx, y: ny });
+
+          if (willEat) {
+            score += 1;
+            // Gentle ramp up.
+            const ramp = BASE_TPS + score * 0.45;
+            tps = clamp(ramp, BASE_TPS, MAX_TPS);
+            updateHUD();
+            announce(`Score ${score}`);
+
+            const occ = new Set(snake.map((p) => key(p.x, p.y)));
+            food = placeFood(occ);
+            if (!food) {
+              end("You filled the board");
+              return;
+            }
+          } else {
+            snake.shift();
+          }
+        }
+
+        function draw() {
+          // Scale canvas for DPR.
+          const rect = canvas.getBoundingClientRect();
+          const dpr = Math.max(1, Math.min(2.5, window.devicePixelRatio || 1));
+          const size = Math.floor(Math.min(rect.width, rect.height));
+          const px = Math.floor(size * dpr);
+          if (canvas.width !== px || canvas.height !== px) {
+            canvas.width = px;
+            canvas.height = px;
+          }
+
+          const W = canvas.width;
+          const H = canvas.height;
+          ctx.clearRect(0, 0, W, H);
+
+          const cell = W / GRID;
+          const pad = Math.max(1, Math.floor(cell * 0.10));
+          const r = Math.max(3, Math.floor(cell * 0.28));
+
+          // Subtle grid.
+          ctx.save();
+          ctx.globalAlpha = 0.22;
+          ctx.strokeStyle = "rgba(255,255,255,0.06)";
+          ctx.lineWidth = Math.max(1, Math.floor(dpr));
+          for (let i = 1; i < GRID; i++) {
+            const p = Math.round(i * cell) + 0.5;
+            ctx.beginPath();
+            ctx.moveTo(p, 0);
+            ctx.lineTo(p, H);
+            ctx.stroke();
+            ctx.beginPath();
+            ctx.moveTo(0, p);
+            ctx.lineTo(W, p);
+            ctx.stroke();
+          }
+          ctx.restore();
+
+          // Food glow.
+          if (food) {
+            const cx = (food.x + 0.5) * cell;
+            const cy = (food.y + 0.5) * cell;
+            const glowR = cell * 0.95;
+            const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, glowR);
+            grad.addColorStop(0, "rgba(255,90,122,0.35)");
+            grad.addColorStop(0.35, "rgba(255,90,122,0.20)");
+            grad.addColorStop(1, "rgba(255,90,122,0)");
+            ctx.fillStyle = grad;
+            ctx.beginPath();
+            ctx.arc(cx, cy, glowR, 0, Math.PI * 2);
+            ctx.fill();
+          }
+
+          // Snake body.
+          const len = snake.length;
+          for (let i = 0; i < len; i++) {
+            const p = snake[i];
+            const x = Math.round(p.x * cell);
+            const y = Math.round(p.y * cell);
+            const w = Math.round(cell);
+            const h = Math.round(cell);
+
+            const t = len <= 1 ? 1 : i / (len - 1);
+            const a = 0.18 + t * 0.82;
+            const fill = `rgba(${Math.round(106 + 40 * (1 - t))}, ${Math.round(
+              228 - 60 * (1 - t)
+            )}, ${Math.round(255 - 40 * (1 - t))}, ${a})`;
+            const stroke = "rgba(255,255,255,0.12)";
+
+            roundRect(ctx, x + pad, y + pad, w - pad * 2, h - pad * 2, r);
+            ctx.fillStyle = fill;
+            ctx.fill();
+            ctx.strokeStyle = stroke;
+            ctx.lineWidth = Math.max(1, Math.floor(1.2 * (window.devicePixelRatio || 1)));
+            ctx.stroke();
+          }
+
+          // Head highlight.
+          const head = snake[snake.length - 1];
+          if (head) {
+            const cx = (head.x + 0.5) * cell;
+            const cy = (head.y + 0.5) * cell;
+            const grad = ctx.createRadialGradient(cx - cell * 0.15, cy - cell * 0.2, 0, cx, cy, cell);
+            grad.addColorStop(0, "rgba(255,255,255,0.18)");
+            grad.addColorStop(1, "rgba(255,255,255,0)");
+            ctx.fillStyle = grad;
+            ctx.beginPath();
+            ctx.arc(cx, cy, cell * 0.95, 0, Math.PI * 2);
+            ctx.fill();
+          }
+
+          // Food.
+          if (food) {
+            const x = food.x * cell;
+            const y = food.y * cell;
