+          for (let y = 0; y < GRID; y++) {
+            for (let x = 0; x < GRID; x++) {
+              if (!occupiedSet.has(key(x, y))) return { x, y };
+            }
+          }
+          return null;
+        }
+
+        let snake;
+        let dir;
+        let queuedDir;
+        let food;
+        let score;
+        let tps;
+        let running = false;
+        let paused = false;
+        let gameOver = false;
+
+        let lastTime = 0;
+        let acc = 0;
+
+        function resetGame() {
+          // Start centered, moving right.
+          const mid = Math.floor(GRID / 2);
+          snake = [
+            { x: mid - 2, y: mid },
+            { x: mid - 1, y: mid },
+            { x: mid, y: mid },
+          ];
+          dir = { x: 1, y: 0 };
+          queuedDir = null;
+          score = 0;
+          tps = BASE_TPS;
+          running = false;
+          paused = false;
+          gameOver = false;
+
+          const occ = new Set(snake.map((p) => key(p.x, p.y)));
+          food = placeFood(occ);
+          updateHUD();
+          setPill("Ready", "ready");
+          showOverlay("Snake", "Use arrow keys to move. Eat the orb. Don’t hit the walls or yourself.");
+          draw();
+        }
+
+        function start() {
+          if (gameOver) return;
+          if (running && !paused) return;
+          running = true;
+          paused = false;
+          setPill("Playing", "playing");
+          hideOverlay();
+          announce("Game started");
+          lastTime = performance.now();
+          acc = 0;
+          requestAnimationFrame(frame);
+        }
+
+        function restart() {
+          resetGame();
+          start();
+        }
+
+        function pause() {
+          if (!running || gameOver) return;
+          paused = true;
+          setPill("Paused", "paused");
+          showOverlay("Paused", "Press Resume or hit Enter to continue.");
+          announce("Game paused");
+        }
+
+        function resume() {
+          if (!running || gameOver) return;
+          if (!paused) return;
+          paused = false;
+          setPill("Playing", "playing");
+          hideOverlay();
+          announce("Game resumed");
+          lastTime = performance.now();
+          acc = 0;
+          requestAnimationFrame(frame);
+        }
+
+        function end(reason) {
+          gameOver = true;
+          running = false;
+          paused = false;
+          setPill("Game Over", "over");
+
+          const msg =
+            (reason ? reason + ". " : "") +
+            `Final score: ${score}. Press Space to restart.`;
+
+          showOverlay("Game Over", msg);
+          announce("Game over. " + msg);
+
+          if (score > bestScore) {
+            bestScore = score;
+            localStorage.setItem(LS_BEST_KEY, String(bestScore));
+            bestEl.textContent = String(bestScore);
+          }
+        }
+
+        function updateHUD() {
+          scoreEl.textContent = String(score);
+          bestEl.textContent = String(bestScore);
+        }
+
+        function showOverlay(title, msg) {
+          overlayTitle.textContent = title;
+          overlayMsg.textContent = msg;
+          overlayCard.hidden = false;
+        }
+
+        function hideOverlay() {
+          overlayCard.hidden = true;
+        }
+
+        function setDirection(next) {
+          // Prevent instantaneous reversal.
+          if (!next) return;
+          const current = queuedDir || dir;
+          if (current.x + next.x === 0 && current.y + next.y === 0) return;
+          queuedDir = next;
+          if (!running && !gameOver) start();
+        }
+
+        function step() {
+          if (!running || paused || gameOver) return;
+
+          if (queuedDir) {
+            dir = queuedDir;
+            queuedDir = null;
+          }
+
+          const head = snake[snake.length - 1];
+          const nx = head.x + dir.x;
+          const ny = head.y + dir.y;
+
+          if (nx < 0 || ny < 0 || nx >= GRID || ny >= GRID) {
+            end("You hit a wall");
+            return;
+          }
+
+          const nextKey = key(nx, ny);
+
+          // If we are not growing, the tail will move away, so allow moving into current tail.
+          const willEat = food && nx === food.x && ny === food.y;
+          const tail = snake[0];
+          const tailKey = key(tail.x, tail.y);
+          const bodySet = new Set(snake.map((p) => key(p.x, p.y)));
+          if (bodySet.has(nextKey) && !( !willEat && nextKey === tailKey)) {
+            end("You ran into yourself");
+            return;
+          }
+
+          // Advance.
+          snake.push({ x: nx, y: ny });
+
+          if (willEat) {
+            score += 1;
+            // Gentle ramp up.
+            const ramp = BASE_TPS + score * 0.45;
+            tps = clamp(ramp, BASE_TPS, MAX_TPS);
+            updateHUD();
+            announce(`Score ${score}`);
+
+            const occ = new Set(snake.map((p) => key(p.x, p.y)));
+            food = placeFood(occ);
+            if (!food) {
+              end("You filled the board");
+              return;
+            }
+          } else {
+            snake.shift();
+          }
+        }
+
+        function draw() {
+          // Scale canvas for DPR.
+          const rect = canvas.getBoundingClientRect();
+          const dpr = Math.max(1, Math.min(2.5, window.devicePixelRatio || 1));
+          const size = Math.floor(Math.min(rect.width, rect.height));
+          const px = Math.floor(size * dpr);
+          if (canvas.width !== px || canvas.height !== px) {
+            canvas.width = px;
+            canvas.height = px;
+          }
+
+          const W = canvas.width;
+          const H = canvas.height;
+          ctx.clearRect(0, 0, W, H);
+
+          const cell = W / GRID;
+          const pad = Math.max(1, Math.floor(cell * 0.10));
+          const r = Math.max(3, Math.floor(cell * 0.28));
+
+          // Subtle grid.
+          ctx.save();
+          ctx.globalAlpha = 0.22;
+          ctx.strokeStyle = "rgba(255,255,255,0.06)";
+          ctx.lineWidth = Math.max(1, Math.floor(dpr));
+          for (let i = 1; i < GRID; i++) {
+            const p = Math.round(i * cell) + 0.5;
+            ctx.beginPath();
+            ctx.moveTo(p, 0);
+            ctx.lineTo(p, H);
+            ctx.stroke();
+            ctx.beginPath();
+            ctx.moveTo(0, p);
+            ctx.lineTo(W, p);
+            ctx.stroke();
+          }
+          ctx.restore();
+
+          // Food glow.
+          if (food) {
+            const cx = (food.x + 0.5) * cell;
+            const cy = (food.y + 0.5) * cell;
+            const glowR = cell * 0.95;
+            const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, glowR);
+            grad.addColorStop(0, "rgba(255,90,122,0.35)");
+            grad.addColorStop(0.35, "rgba(255,90,122,0.20)");
+            grad.addColorStop(1, "rgba(255,90,122,0)");
+            ctx.fillStyle = grad;
+            ctx.beginPath();
+            ctx.arc(cx, cy, glowR, 0, Math.PI * 2);
+            ctx.fill();
+          }
+
+          // Snake body.
+          const len = snake.length;
+          for (let i = 0; i < len; i++) {
+            const p = snake[i];
+            const x = Math.round(p.x * cell);
+            const y = Math.round(p.y * cell);
+            const w = Math.round(cell);
+            const h = Math.round(cell);
+
+            const t = len <= 1 ? 1 : i / (len - 1);
+            const a = 0.18 + t * 0.82;
+            const fill = `rgba(${Math.round(106 + 40 * (1 - t))}, ${Math.round(
+              228 - 60 * (1 - t)
+            )}, ${Math.round(255 - 40 * (1 - t))}, ${a})`;
+            const stroke = "rgba(255,255,255,0.12)";
+
+            roundRect(ctx, x + pad, y + pad, w - pad * 2, h - pad * 2, r);
+            ctx.fillStyle = fill;
+            ctx.fill();
+            ctx.strokeStyle = stroke;
+            ctx.lineWidth = Math.max(1, Math.floor(1.2 * (window.devicePixelRatio || 1)));
+            ctx.stroke();
+          }
+
+          // Head highlight.
+          const head = snake[snake.length - 1];
+          if (head) {
+            const cx = (head.x + 0.5) * cell;
+            const cy = (head.y + 0.5) * cell;
+            const grad = ctx.createRadialGradient(cx - cell * 0.15, cy - cell * 0.2, 0, cx, cy, cell);
+            grad.addColorStop(0, "rgba(255,255,255,0.18)");
+            grad.addColorStop(1, "rgba(255,255,255,0)");
+            ctx.fillStyle = grad;
+            ctx.beginPath();
+            ctx.arc(cx, cy, cell * 0.95, 0, Math.PI * 2);
+            ctx.fill();
+          }
+
+          // Food.
+          if (food) {
+            const x = food.x * cell;
+            const y = food.y * cell;
+            const cx = x + cell / 2;
+            const cy = y + cell / 2;
+            const rr = Math.max(4, cell * 0.26);
+
+            const orb = ctx.createRadialGradient(cx - rr * 0.3, cy - rr * 0.3, 0, cx, cy, rr * 2.1);
+            orb.addColorStop(0, "rgba(255,255,255,0.95)");
+            orb.addColorStop(0.25, "rgba(255,170,190,0.95)");
+            orb.addColorStop(0.55, "rgba(255,90,122,0.92)");
+            orb.addColorStop(1, "rgba(255,90,122,0.0)");
+
+            ctx.fillStyle = orb;
+            ctx.beginPath();
+            ctx.arc(cx, cy, rr * 2.1, 0, Math.PI * 2);
+            ctx.fill();
+
+            ctx.fillStyle = "rgba(255,90,122,0.95)";
+            ctx.beginPath();
+            ctx.arc(cx, cy, rr, 0, Math.PI * 2);
+            ctx.fill();
+            ctx.strokeStyle = "rgba(255,255,255,0.16)";
+            ctx.lineWidth = Math.max(1, Math.floor((window.devicePixelRatio || 1)));
+            ctx.stroke();
+          }
+
+          // Paused vignette.
+          if (paused) {
+            const g = ctx.createRadialGradient(W * 0.5, H * 0.5, W * 0.15, W * 0.5, H * 0.5, W * 0.75);
+            g.addColorStop(0, "rgba(0,0,0,0.0)");
+            g.addColorStop(1, "rgba(0,0,0,0.35)");
+            ctx.fillStyle = g;
+            ctx.fillRect(0, 0, W, H);
+          }
+        }
+
+        function roundRect(c, x, y, w, h, r) {
+          const rr = Math.min(r, w / 2, h / 2);
+          c.beginPath();
+          c.moveTo(x + rr, y);
+          c.arcTo(x + w, y, x + w, y + h, rr);
+          c.arcTo(x + w, y + h, x, y + h, rr);
+          c.arcTo(x, y + h, x, y, rr);
+          c.arcTo(x, y, x + w, y, rr);
+          c.closePath();
+        }
+
+        function frame(now) {
+          if (!running || paused || gameOver) {
+            draw();
+            return;
+          }
+
+          const dt = Math.min(0.05, (now - lastTime) / 1000);
+          lastTime = now;
+          acc += dt;
+
+          const stepTime = 1 / tps;
+          while (acc >= stepTime) {
+            step();
+            acc -= stepTime;
+            if (gameOver) break;
+          }
+          draw();
+          if (!gameOver && !paused) requestAnimationFrame(frame);
+        }
+
+        // Controls.
+        window.addEventListener(
+          "keydown",
+          (e) => {
+            const isArrow = e.key in dirs;
+            if (isArrow) e.preventDefault();
+
+            if (e.key in dirs) {
+              setDirection(dirs[e.key]);
+              return;
+            }
+
+            if (e.key === " " || e.key === "Spacebar") {
+              e.preventDefault();
+              restart();
+              return;
+            }
+
+            if (e.key === "Enter") {
+              if (gameOver) {
+                restart();
+              } else if (!running) {
+                start();
+              } else if (paused) {
+                resume();
+              } else {
+                pause();
+              }
+              return;
+            }
+
+            if (e.key === "Escape") {
+              if (running && !paused && !gameOver) pause();
+              return;
+            }
+          },
+          { passive: false }
+        );
+
+        btnStart.addEventListener("click", start);
+        btnRestart.addEventListener("click", restart);
+        btnPause.addEventListener("click", pause);
+        btnResume.addEventListener("click", resume);
+
+        window.addEventListener("blur", () => {
+          // Avoid losing the game because of a stuck key or lost focus.
+          if (running && !paused && !gameOver) pause();
+        });
+
+        window.addEventListener("resize", () => {
+          draw();
+        });
+
+        // Initial paint.
+        resetGame();
+      })();
+    </script>
+  </body>
+</html>
